def count_primes(n):
    sieve = [True] * n
    sieve[0:2] = [False, False]  # 0 and 1 are not prime numbers
    for current_prime in range(2, int(n**0.5) + 1):
        if sieve[current_prime]:
            for multiple in range(current_prime*2, n, current_prime):
                sieve[multiple] = False
    return sum(1 for is_prime in sieve if is_prime)

def f(n):
    return count_primes(n)

