def f(expr: str) -> int:
    def apply_operator():
        op = operators.pop()
        v2 = values.pop()
        v1 = values.pop()
        if op == '+':
            values.append(v1 + v2)
        elif op == '-':
            values.append(v1 - v2)
        elif op == '*':
            values.append(v1 * v2)

    def precedence(op: str) -> int:
        if op in ['+', '-']:
            return 1
        elif op == '*':
            return 2
        return 0

    values, operators = [], []
    i = 0
    while i < len(expr):
        if expr[i].isdigit():
            j = i
            while i < len(expr) and expr[i].isdigit():
                i += 1
            values.append(int(expr[j:i]))
        elif expr[i] in ['+', '-', '*']:
            while operators and operators[-1] != '(' and precedence(operators[-1]) >= precedence(expr[i]):
                apply_operator()
            operators.append(expr[i])
            i += 1
        elif expr[i] == '(':
            operators.append(expr[i])
            i += 1
        elif expr[i] == ')':
            while operators[-1] != '(':
                apply_operator()
            operators.pop()
            i += 1
    while operators:
        apply_operator()
    return values[0]
